function routeTo(route){
  $$('.page').forEach(page => page.classList.toggle('active', page.id === route));
  $$('.nav-link').forEach(link => link.classList.toggle('active', link.dataset.route === route));
  $('.sidebar').classList.remove('open');
  $('#menuButton').setAttribute('aria-expanded','false');
  window.scrollTo({top:0,behavior:'smooth'});
  if(route === 'dashboard') requestAnimationFrame(()=>$('#analysisViewMode').value==='partner'?drawPairCourt(liveAnalysisResult?.pair_analysis):drawHeatmap());
  if(route === 'progress') renderScoreTracker();
  if(route === 'benchmarks') renderBenchmarks();
  if(route === 'clubs') loadClubs();
}

$$('[data-route]').forEach(el => el.addEventListener('click', e => { e.preventDefault(); routeTo(el.dataset.route); }));
$('#menuButton').addEventListener('click', () => {
  const open = $('.sidebar').classList.toggle('open');
  $('#menuButton').setAttribute('aria-expanded', String(open));
});

function getAllMatches(){const saved=JSON.parse(localStorage.getItem('padeliqMatches')||'[]'),filtered=saved.filter(match=>!isLegacyDemoMatch(match)),matches=filtered.map(match=>match.result?match:{...match,score:null});if(JSON.stringify(matches)!==JSON.stringify(saved))localStorage.setItem('padeliqMatches',JSON.stringify(matches));return matches;}

function renderMatches(){
  const matches=getAllMatches();
  $('#matchList').innerHTML = matches.length?matches.map((m,index) => {const target=`custom:${index}`;return `<article class="match-card"><div class="match-date">${escapeHtml(m.date||'—')}<small>${escapeHtml(m.month||'')}</small></div><div><h3>${escapeHtml(m.title)}</h3><p>${escapeHtml([m.place,m.court,m.racket,m.matchScore].filter(Boolean).join(' · ')||m.detail||'')}</p></div><div class="match-score"><strong>${m.score??'—'}</strong><small>POSITION</small></div><div class="match-actions"><button class="secondary-button" data-view-match="${target}">View</button><button class="secondary-button" data-edit-match="${target}">Edit details</button><button class="danger-button" data-delete-match="${target}" aria-label="Delete ${escapeHtml(m.title)}">Delete</button></div></article>`}).join(''):'<div class="panel"><h2>No saved matches</h2><p>Upload a match to create your first report.</p></div>';
  $('#matchesCount').textContent = matches.length;
  const latestScored=matches.find(match=>match.score!=null&&Number.isFinite(Number(match.score)));if(!latestScored){$('#overallScore').textContent='—';$('.score-ring').style.setProperty('--score',0);$('#positionTrendPill').textContent='Awaiting analysis';}else{$('#overallScore').textContent=Math.round(Number(latestScored.score));$('.score-ring').style.setProperty('--score',Number(latestScored.score));$('#positionTrendPill').textContent='Video analysis score';}
  $$('[data-view-match]').forEach(button => button.addEventListener('click', () => {const match=resolveMatch(button.dataset.viewMatch);if(match?.result){liveAnalysisResult=match.result;applyRealResult(match.result);}$('#overallScore').textContent=match?.score??'—';routeTo('dashboard');showToast('Showing the selected match report'); }));
  $$('[data-edit-match]').forEach(button=>button.addEventListener('click',()=>openEditMatch(button.dataset.editMatch)));
  $$('[data-delete-match]').forEach(button=>button.addEventListener('click',()=>deleteMatch(button.dataset.deleteMatch)));
  renderScoreTracker();
}

function resolveMatch(target){const [,value]=target.split(':'),custom=getAllMatches();return custom[Number(value)];}
function openEditMatch(target){const match=resolveMatch(target);if(!match)return;$('#editMatchIndex').value=target;$('#editMatchName').value=match.title||'';$('#editMatchDate').value=match.isoDate||'';$('#editMatchPlace').value=match.place||'';$('#editMatchCourt').value=match.court||'';$('#editMatchRacket').value=match.racket||'';$('#editMatchScore').value=match.matchScore||'';$('#editMatchDialog').showModal();}
$('#closeEditMatch').addEventListener('click',()=>$('#editMatchDialog').close());$('#cancelEditMatch').addEventListener('click',()=>$('#editMatchDialog').close());
$('#editMatchForm').addEventListener('submit',event=>{event.preventDefault();const target=$('#editMatchIndex').value,[,value]=target.split(':'),custom=getAllMatches(),original=resolveMatch(target);if(!original)return;const date=new Date(`${$('#editMatchDate').value}T12:00:00`),months=['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];const updated={...original,title:$('#editMatchName').value.trim(),isoDate:$('#editMatchDate').value,date:String(date.getDate()).padStart(2,'0'),month:months[date.getMonth()],place:$('#editMatchPlace').value.trim(),court:$('#editMatchCourt').value.trim(),racket:$('#editMatchRacket').value.trim(),matchScore:$('#editMatchScore').value.trim()};custom[Number(value)]=updated;queueMatchSave(updated);localStorage.setItem('padeliqMatches',JSON.stringify(custom));$('#editMatchDialog').close();renderMatches();showToast('Match details updated');});

async function deleteMatch(target){
  const [,value]=target.split(':'),custom=getAllMatches(),match=custom[Number(value)];if(!match)return;
  if(!window.confirm(`Delete “${match.title}” and its report and score? This cannot be undone.`))return;
  const button=$(`[data-delete-match="${CSS.escape(target)}"]`);if(button)button.disabled=true;
  const pending=pendingMatchSaves.get(match.id);if(pending)await pending;const savedMatch=getAllMatches().find(item=>item.id===match.id)||match,remoteId=savedMatch.remoteId;
  if(currentUser&&remoteId&&!backendReady){if(button)button.disabled=false;showToast('Cloud deletion is temporarily unavailable. Please try again.');return;}
  if(currentUser&&backendReady&&remoteId){const {error}=await supabaseClient.from('matches').delete().eq('user_id',currentUser.id).eq('id',remoteId);if(error){if(button)button.disabled=false;console.warn('Match deletion failed',error.message);showToast('The match could not be deleted. Please try again.');return;}}
  const latest=getAllMatches(),removeIndex=latest.findIndex(item=>item.id===match.id);if(removeIndex>=0)latest.splice(removeIndex,1);localStorage.setItem('padeliqMatches',JSON.stringify(latest));renderMatches();showToast('Match, video metadata and analysis deleted');
}

function renderTrend(windowSize=Number(localStorage.getItem('padeliqTrendWindow')||5)){
  const chosen=getAllMatches().slice().sort((a,b)=>String(a.isoDate||'').localeCompare(String(b.isoDate||''))).filter(m=>m.score!=null&&Number.isFinite(Number(m.score))).slice(-windowSize),values=chosen.map(m=>Number(m.score)),labels=chosen.map(m=>`${m.date} ${m.month}`);if(!values.length){$('#trendChart').innerHTML='<p class="empty-state">Complete a video analysis to see your positioning trajectory.</p>';$('#averageScore').textContent='—';$('#currentTrend').textContent='Awaiting analysis';return;}
  const width=820,height=260,pad=42,min=Math.max(0,Math.min(...values)-8),max=Math.min(100,Math.max(...values)+8);
  const x=i=>values.length===1?width/2:pad+i*(width-pad*2)/(values.length-1), y=v=>height-pad-(v-min)*(height-pad*2)/Math.max(1,max-min);
  const points=values.map((v,i)=>`${x(i)},${y(v)}`).join(' ');
  const grid=[min,Math.round((min+max)/2),max].map(v=>`<line x1="${pad}" y1="${y(v)}" x2="${width-pad}" y2="${y(v)}" stroke="#e2e9e5"/><text x="4" y="${y(v)+4}" fill="#7b8882" font-size="11">${v}</text>`).join('');
  const dots=values.map((v,i)=>`<circle cx="${x(i)}" cy="${y(v)}" r="5" fill="#19a974" stroke="white" stroke-width="3"/><text x="${x(i)}" y="${y(v)-13}" text-anchor="middle" fill="#13251f" font-size="11" font-weight="700">${v}</text><text x="${x(i)}" y="${height-8}" text-anchor="middle" fill="#7b8882" font-size="10">${labels[i]}</text>`).join('');
  $('#trendChart').innerHTML=`<svg viewBox="0 0 ${width} ${height}" aria-hidden="true">${grid}<polyline points="${points}" fill="none" stroke="#1688c8" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"/>${dots}</svg>`;const average=Math.round(values.reduce((a,b)=>a+b,0)/values.length),delta=values.length>1?values.at(-1)-values[0]:0;$('#averageScore').textContent=average;$('#averageScoreContext').textContent=`Across the last ${values.length} matches`;$('#currentTrend').textContent=delta>0?'↗ Rising':delta<0?'↘ Falling':'→ Steady';$('#trendContext').textContent=`${delta>0?'+':''}${delta} points in this window`;$('#trendDelta').textContent=`${delta>0?'+':''}${delta} points`;$('#trendTitle').textContent=`Last ${values.length} matches`;
}

function scoreOutcome(score){if(!score)return null;let won=0,lost=0;for(const set of score.split(',')){const nums=set.match(/\d+/g)?.map(Number);if(!nums||nums.length<2)continue;if(nums[0]>nums[1])won++;else if(nums[1]>nums[0])lost++;}return won===lost?null:won>lost?'W':'L';}
function renderScoreTracker(){const matches=getAllMatches(),record=matches.map(m=>scoreOutcome(m.matchScore)).filter(Boolean),wins=record.filter(x=>x==='W').length,losses=record.filter(x=>x==='L').length;$('#matchRecord').textContent=`${wins}–${losses}`;$('#scoreHistoryList').innerHTML=matches.map(m=>`<div class="score-history-row"><span class="result-badge ${scoreOutcome(m.matchScore)==='W'?'win':'loss'}">${scoreOutcome(m.matchScore)||'—'}</span><div><strong>${escapeHtml(m.title)}</strong><small>${escapeHtml([m.isoDate,m.racket].filter(Boolean).join(' · '))}</small></div><b>${escapeHtml(m.matchScore||'Score not entered')}</b><span>${m.score??'—'}</span></div>`).join('');const selected=Number(localStorage.getItem('padeliqTrendWindow')||5);$$('[data-trend-window]').forEach(button=>button.classList.toggle('active',Number(button.dataset.trendWindow)===selected));renderTrend(selected);}
$$('[data-trend-window]').forEach(button=>button.addEventListener('click',()=>{localStorage.setItem('padeliqTrendWindow',button.dataset.trendWindow);renderScoreTracker();}));

function referencePercentile(score){return Math.max(3,Math.min(97,Math.round(100/(1+Math.exp(-(Number(score)-70)/7)))));}
function ageBenchmarkBand(age){const value=Number(age);if(!Number.isFinite(value)||value<13||value>100)return null;if(value<20)return 'Under 20';if(value<35)return '20–35';if(value<45)return '35–45';return '45+';}
function ordinal(value){const number=Math.round(Number(value)),lastTwo=number%100;if(lastTwo>=11&&lastTwo<=13)return `${number}th`;return `${number}${number%10===1?'st':number%10===2?'nd':number%10===3?'rd':'th'}`;}
function latestMeasuredMatch(){return getAllMatches().find(match=>match.result?.summary)||null;}
function renderBenchmarks(){
  const profile=JSON.parse(localStorage.getItem('padeliqProfile')||'{}'),matches=getAllMatches(),measured=latestMeasuredMatch(),profileParts=[],ageBand=ageBenchmarkBand(profile.age),validGenders=['Woman','Man','Non-binary','Self-describe'],validLevels=['Beginner','Intermediate','Competitive','Advanced'];
  if(ageBand)profileParts.push(`Age: ${ageBand}`);if(validGenders.includes(profile.gender))profileParts.push(`Gender: ${profile.gender}`);if(validLevels.includes(profile.level))profileParts.push(`Level: ${profile.level}`);
  $('#cohortChips').innerHTML=profileParts.length?profileParts.map(item=>`<span>${escapeHtml(item)}</span>`).join(''):'<span class="missing-chip">Complete age, gender and level in Profile</span>';
  $('#cohortTitle').textContent=profileParts.length===3?'3 profile attributes selected':'Add age, gender and level to build your cohort';
  $('#cohortStatus').textContent='Cohort building';
  ['positionPercentile','coveragePercentile','recoveryPercentile'].forEach(id=>{$('#'+id).textContent='—';$('#'+id+'Bar').style.width='0%';});
  const scores=matches.map(m=>Number(m.score)).filter(Number.isFinite),score=scores[0];
  if(Number.isFinite(score)){const percentile=referencePercentile(score);$('#referencePercentile').textContent=`${ordinal(percentile)} percentile`;$('#referenceHeadline').textContent=percentile>=75?'Strong positioning reference':percentile>=50?'Developing above the reference midpoint':'Clear positioning upside';$('#referenceInsight').textContent=`Your latest position score of ${score} is shown against the fixed early-stage reference distribution.`;}else{$('#referencePercentile').textContent='—';$('#referenceHeadline').textContent='Complete an analysed match';$('#referenceInsight').textContent='Your positioning score will create an initial reference estimate.';}
  if(measured){const summary=measured.result.summary;$('#coveragePercentileText').textContent=`Latest measured tracking coverage: ${summary.tracking_coverage_percent}%`;$('#recoveryPercentileText').textContent=summary.recovery_within_two_seconds_percent==null?'Recovery baseline is still being established':`Recovery within two seconds: ${summary.recovery_within_two_seconds_percent}%`;}
  renderMistakes(measured);
}
function renderMistakes(match){
  const container=$('#mistakeCards');if(!match){container.innerHTML=`<article class="mistake-card panel baseline-needed"><span>◎</span><div><small>BASELINE NEEDED</small><h3>Analyse a match to identify positioning mistakes</h3><p>Once player tracking is available, this section will evaluate coverage gaps, court-zone balance, partner-line recovery and repeated transition patterns.</p></div></article>`;return;}
  const s=match.result.summary,positions=match.result.positions||[],mistakes=[];
  if(s.tracking_coverage_percent<80)mistakes.push({level:'high',title:'Tracking or court visibility gaps',evidence:`Only ${s.tracking_coverage_percent}% of sampled frames tracked reliably.`,fix:'Use a fixed, full-court camera angle and verify the selected player before analysis.'});
  if(s.recovery_within_two_seconds_percent!=null&&s.recovery_within_two_seconds_percent<65)mistakes.push({level:'high',title:'Slow return to a useful base',evidence:`${s.recovery_within_two_seconds_percent}% of recoveries completed within two seconds.`,fix:'After contact, use the first two steps to recover toward your partner line and protect the middle.'});
  if(s.transition_zone_percent>38)mistakes.push({level:'medium',title:'Too much time caught in transition',evidence:`${s.transition_zone_percent}% of tracked time was spent between stable zones.`,fix:'Commit to advancing or retreating with your partner instead of holding the corridor.'});
  if(s.back_court_percent>58)mistakes.push({level:'medium',title:'Pinned too deep for too long',evidence:`${s.back_court_percent}% of tracked time remained in the back court.`,fix:'Look for the first neutral or weak ball that lets both players advance together.'});
  if(s.net_zone_percent<24)mistakes.push({level:'medium',title:'Low net presence',evidence:`Net-zone presence was ${s.net_zone_percent}%.`,fix:'Use lobs and controlled low balls to earn the net, then hold a connected line.'});
  if(positions.length){const meanX=positions.reduce((sum,p)=>sum+p.x,0)/positions.length;if(meanX<3||meanX>7)mistakes.push({level:'low',title:'Coverage concentrated in one channel',evidence:'The movement path is heavily weighted to one side of the court.',fix:'Stay responsible for your channel while moving enough to protect the middle with your partner.'});}
  const llmFixes=match.result.ai_feedback?.improvements||[];llmFixes.slice(0,1).forEach(text=>mistakes.push({level:'ai',title:'AI video observation',evidence:text,fix:'Compare this observation with the heatmap and review the relevant footage with a coach.'}));
  if(!mistakes.length)mistakes.push({level:'low',title:'No dominant positioning error detected',evidence:'Measured zone balance and recovery are within the initial thresholds.',fix:'Keep building the sample across more matches to reveal smaller repeatable patterns.'});
  container.innerHTML=mistakes.slice(0,4).map((item,index)=>`<article class="mistake-card panel"><span class="mistake-number">${index+1}</span><div><small class="severity ${item.level}">${item.level==='ai'?'LLM SIGNAL':item.level.toUpperCase()+' PRIORITY'}</small><h3>${escapeHtml(item.title)}</h3><p>${escapeHtml(item.evidence)}</p><div class="mistake-fix"><b>How to improve</b>${escapeHtml(item.fix)}</div></div></article>`).join('');
}

function seededPoints(mode){
  const seeds={all:[[.25,.28,1],[.34,.37,.8],[.28,.53,.72],[.65,.35,.5],[.56,.58,.43],[.22,.72,.36]],attack:[[.27,.24,1],[.39,.28,.7],[.7,.31,.48],[.53,.4,.35]],defence:[[.25,.72,1],[.34,.62,.75],[.65,.76,.55],[.48,.58,.4]]};
  return seeds[mode] || seeds.all;
}

function renderPositioningCoach(summary){
  const panel=$('#positioningCoachPanel');if(!summary||summary.quality_status==='unreliable'){panel.hidden=true;return;}panel.hidden=false;
  const net=Number(summary.net_zone_percent||0),back=Number(summary.back_court_percent||0),recovery=summary.recovery_within_two_seconds_percent==null?null:Number(summary.recovery_within_two_seconds_percent);
  $('#netCoachValue').textContent=`${net}%`;$('#backCoachValue').textContent=`${back}%`;$('#recoveryCoachValue').textContent=recovery==null?'Baseline needed':`${recovery}%`;$('#positioningQuality').textContent=`${summary.tracking_coverage_percent}% tracking`;
  $('#netCoachRecommendation').textContent=net<22?'Your net presence was limited. Use a high, deep lob or controlled low ball to earn time to advance with your partner; stop and split-step before the opponent contacts.':net>48?'You spent a large share of time close to the net. Keep the pressure, but avoid crowding it: preserve space to defend your feet and recognise the lob early.':'Your net presence is in a useful initial range. Focus on arriving with your partner, holding a connected line and retreating together when opponents gain time.';
  $('#recoveryCoachRecommendation').textContent=recovery==null?'The clip did not contain enough clear excursions and returns for a stable recovery baseline. Build the sample with a longer match.':recovery<60?'Prioritise the first two steps after every action. Recover toward your useful base and your partner’s horizontal line before watching the outcome of your shot.':recovery<80?'Recovery is developing. Make the first step directional, use small adjustment steps near base and split-step as the opponent prepares to strike.':'Recovery was a strength in this sample. Maintain the habit while checking that speed does not pull you across your partner’s channel.';
  $('#backCoachRecommendation').textContent=back>60?'You were pinned deep for much of the sample. Defend patiently, then use the first neutral ball—often a lob—to move both players forward together.':back<28?'You spent relatively little time deep. That may reflect good pressure, but check the heatmap for rushed advances; retreat early when opponents can attack or lob comfortably.':'Your defensive-zone share is reasonably balanced. Improve the quality of the transition: leave the back only behind a ball that gives both partners time to advance.';
  const insight=net<22?`You reached the net zone for ${net}% of tracked time. Your clearest opportunity is earning the net with more margin and advancing as a pair.`:back>60?`${back}% of tracked time was deep in the court. Look for neutral balls that allow a coordinated transition forward.`:recovery!=null&&recovery<60?`Only ${recovery}% of measured excursions returned to base within two seconds. Earlier first-step recovery should close the largest gaps.`:`Your zone balance is broadly useful in this sample. Review the base marker and isolated heatmap hotspots for smaller efficiency gains.`;
  $('#coverageInsightText').textContent=insight;
}

function drawHeatmap(){
  const canvas=$('#courtHeatmap'); if(!canvas || !canvas.offsetParent) return;
  const dpr=window.devicePixelRatio||1,w=560,h=680; canvas.width=w*dpr;canvas.height=h*dpr;
  const ctx=canvas.getContext('2d');ctx.scale(dpr,dpr);ctx.clearRect(0,0,w,h);
  const x=55,y=30,cw=450,ch=610;
  ctx.fillStyle='#65b3d8';ctx.fillRect(x,y,cw,ch);
  ctx.fillStyle='rgba(40,112,190,.17)';ctx.fillRect(x,y,cw,ch*.3);ctx.fillRect(x,y+ch*.7,cw,ch*.3);
  ctx.fillStyle='rgba(51,211,137,.18)';ctx.fillRect(x,y+ch*.4,cw,ch*.2);
  const mode=$('#heatmapFilter').value,rawPositions=liveAnalysisResult?.positions||[],filteredPositions=mode==='attack'?rawPositions.filter(p=>p.y>=8&&p.y<=12):mode==='defence'?rawPositions.filter(p=>p.y<=6||p.y>=14):rawPositions;
  const points=rawPositions.length
    ? filteredPositions.map(p=>[Math.max(0,Math.min(1,p.x/10)),Math.max(0,Math.min(1,p.y/20)),p.source==='interpolated'?.28:.48])
    : seededPoints($('#heatmapFilter').value);
  points.forEach(([px,py,intensity])=>{
    const gx=x+px*cw,gy=y+py*ch,r=110*intensity+45;
    const g=ctx.createRadialGradient(gx,gy,5,gx,gy,r);
    g.addColorStop(0,`rgba(240,88,63,${.72*intensity})`);g.addColorStop(.32,`rgba(246,210,82,${.56*intensity})`);g.addColorStop(.66,`rgba(68,208,147,${.3*intensity})`);g.addColorStop(1,'rgba(65,171,195,0)');ctx.fillStyle=g;ctx.fillRect(gx-r,gy-r,r*2,r*2);
  });
  ctx.strokeStyle='rgba(255,255,255,.9)';ctx.lineWidth=3;ctx.strokeRect(x,y,cw,ch);
  ctx.beginPath();ctx.moveTo(x,y+ch/2);ctx.lineTo(x+cw,y+ch/2);ctx.moveTo(x+cw/2,y);ctx.lineTo(x+cw/2,y+ch);ctx.moveTo(x,y+145);ctx.lineTo(x+cw,y+145);ctx.moveTo(x,y+ch-145);ctx.lineTo(x+cw,y+ch-145);ctx.stroke();
  ctx.strokeStyle='#174d6a';ctx.lineWidth=7;ctx.beginPath();ctx.moveTo(x-10,y+ch/2);ctx.lineTo(x+cw+10,y+ch/2);ctx.stroke();
  ctx.fillStyle='rgba(255,255,255,.9)';ctx.font='600 13px DM Sans';ctx.textAlign='center';ctx.fillText('NET',x+cw-28,y+ch/2-11);ctx.fillText('YOUR SIDE',x+cw/2,y+ch-18);
  ctx.font='700 10px DM Sans';ctx.fillStyle='rgba(255,255,255,.88)';ctx.fillText('BACK-COURT ZONE',x+cw/2,y+18);ctx.fillText('NET-PRESSURE ZONE',x+cw/2,y+ch/2+18);ctx.fillText('BACK-COURT ZONE',x+cw/2,y+ch-8);
  const outcomes=(liveAnalysisResult?.rallies||[]).filter(r=>r.x!=null&&r.y!=null&&(mode==='all'||(mode==='attack'?r.zone==='net':r.zone==='back')));
  outcomes.forEach(rally=>{const rx=x+Math.max(0,Math.min(1,rally.x/10))*cw,ry=y+Math.max(0,Math.min(1,rally.y/20))*ch,colour=rally.outcome==='won'?'#0b8f60':rally.outcome==='lost'?'#d4473e':'#8095a0';if(rally.partner_x!=null&&rally.partner_y!=null){const px=x+Math.max(0,Math.min(1,rally.partner_x/10))*cw,py=y+Math.max(0,Math.min(1,rally.partner_y/20))*ch;ctx.strokeStyle=colour;ctx.globalAlpha=.7;ctx.lineWidth=2;ctx.setLineDash([5,4]);ctx.beginPath();ctx.moveTo(rx,ry);ctx.lineTo(px,py);ctx.stroke();ctx.setLineDash([]);ctx.globalAlpha=1;ctx.fillStyle='#756ce0';ctx.strokeStyle='#fff';ctx.beginPath();ctx.arc(px,py,7,0,Math.PI*2);ctx.fill();ctx.stroke();}ctx.fillStyle=colour;ctx.strokeStyle='#fff';ctx.lineWidth=3;ctx.beginPath();ctx.arc(rx,ry,10,0,Math.PI*2);ctx.fill();ctx.stroke();ctx.fillStyle='#fff';ctx.font='800 10px DM Sans';ctx.fillText(rally.outcome==='won'?'W':rally.outcome==='lost'?'L':'?',rx,ry+3.5);});
  if(rawPositions.length){const sortedX=rawPositions.map(p=>p.x).sort((a,b)=>a-b),sortedY=rawPositions.map(p=>p.y).sort((a,b)=>a-b),middle=Math.floor(rawPositions.length/2),medianX=sortedX[middle],medianY=sortedY[middle],bx=x+medianX/10*cw,by=y+medianY/20*ch;ctx.strokeStyle='#fff';ctx.lineWidth=3;ctx.setLineDash([7,5]);ctx.beginPath();ctx.arc(bx,by,24,0,Math.PI*2);ctx.stroke();ctx.setLineDash([]);ctx.fillStyle='#fff';ctx.font='800 9px DM Sans';ctx.fillText('BASE',bx,by-30);}
}

function setAnalysisView(mode){const pair=liveAnalysisResult?.pair_analysis,partnerMode=mode==='partner'&&pair;$('#analysisViewMode').value=partnerMode?'partner':'single';$('#dashboard').classList.toggle('partner-view',Boolean(partnerMode));$('#partnerAnalysisView').hidden=!partnerMode;requestAnimationFrame(()=>partnerMode?drawPairCourt(pair):drawHeatmap());}
