function formatMatchTime(seconds){const value=Math.max(0,Math.round(Number(seconds)||0));return `${Math.floor(value/60)}:${String(value%60).padStart(2,'0')}`;}
function renderRallyOutcomes(rallies,pending=false,job=null){
  const panel=$('#rallyOutcomePanel');if(!panel)return;const accepted=rallies.filter(r=>r.outcome==='won'||r.outcome==='lost');if(!rallies.length&&!pending){panel.hidden=true;return;}panel.hidden=false;if(!rallies.length){const progress=Number(job?.progress)||0,message=job?.message||'Reviewing likely rally endings';$('#classifiedRallies').textContent=progress?`${progress}%`:'…';$('#classifiedContext').textContent=message;$('#wonRallies').textContent='—';$('#wonContext').textContent='Awaiting confident calls';$('#lostRallies').textContent='—';$('#lostContext').textContent='Awaiting confident calls';$('#outcomeInsight').textContent='Your positioning report is ready. Estimated outcomes and both players’ positions will appear here as the separate review completes.';$('#rallyOutcomeList').innerHTML=`<div class="rally-outcome-row"><span>AI review running</span><b>${escapeHtml(message)}</b><span>Keep this report open for live progress. Returning later will reconnect while the worker remains active.</span></div>`;$('#outcomeConfidence').textContent=progress?`${progress}% processed`:'Processing';return;}const won=accepted.filter(r=>r.outcome==='won'),lost=accepted.filter(r=>r.outcome==='lost'),unknown=rallies.length-accepted.length,winRate=accepted.length?Math.round(won.length/accepted.length*100):null;
  $('#classifiedRallies').textContent=accepted.length;$('#classifiedContext').textContent=`${unknown} uncertain ${unknown===1?'candidate':'candidates'} excluded`;$('#wonRallies').textContent=won.length;$('#wonContext').textContent=winRate==null?'No confident calls':`${winRate}% of classified points`;$('#lostRallies').textContent=lost.length;$('#lostContext').textContent=accepted.length?`${100-winRate}% of classified points`:'No confident calls';
  const zoneStats=['net','transition','back'].map(zone=>{const items=accepted.filter(r=>r.zone===zone),wins=items.filter(r=>r.outcome==='won').length;return {zone,total:items.length,rate:items.length?Math.round(wins/items.length*100):null};}).filter(item=>item.total);const best=[...zoneStats].sort((a,b)=>b.rate-a.rate)[0],weak=[...zoneStats].sort((a,b)=>a.rate-b.rate)[0];$('#outcomeInsight').textContent=best&&weak&&best.zone!==weak.zone?`Your strongest estimated point-ending position was the ${best.zone} zone (${best.rate}% won). The ${weak.zone} zone was least successful (${weak.rate}% won); review the red court markers for repeatable positioning patterns.`:'More confidently classified rallies are needed before comparing court zones.';
  $('#rallyOutcomeList').innerHTML=rallies.slice(0,16).map(r=>{const url=footageMomentUrl(r.end_seconds);return `<div class="rally-outcome-row ${r.outcome}"><span>${url?`<a href="${url}" target="_blank" rel="noopener">${formatMatchTime(r.end_seconds)} ↗</a>`:formatMatchTime(r.end_seconds)}</span><b>${r.outcome==='unknown'?'Excluded':`Likely ${r.outcome}`}</b><span>${escapeHtml(r.reason||'Insufficient visible evidence')} · ${Math.round((r.confidence||0)*100)}% confidence${r.partner_x!=null?' · both-player positions mapped':''}</span></div>`;}).join('');$('#outcomeConfidence').textContent=`${accepted.length}/${rallies.length} accepted`;
}
async function fetchOutcomeAnalysis(result,attempt=0){
  const token=result?.diagnostic_token;if(!token||attempt>2160)return;try{const base=analysisApi.replace(/\/$/,''),url=`${base}/outcomes/${encodeURIComponent(token)}`;let response;if(attempt===0){const form=new FormData();form.append('positions',JSON.stringify(result.positions||[]));form.append('partner_positions',JSON.stringify(result.pair_analysis?.partner_positions||[]));response=await fetch(url,{method:'POST',body:form});}else response=await fetch(url);if(!response.ok)throw new Error(`Outcome result unavailable (${response.status})`);const job=await response.json();if(job.status==='complete'){result.rallies=job.rallies||[];liveAnalysisResult=result;renderRallyOutcomes(result.rallies);drawHeatmap();if($('#analysisViewMode')?.value==='partner')drawPairCourt(result.pair_analysis);const matches=JSON.parse(localStorage.getItem('padeliqMatches')||'[]'),match=matches.find(item=>item.result?.diagnostic_token===token);if(match){match.result=result;localStorage.setItem('padeliqMatches',JSON.stringify(matches));queueMatchSave(match);}showToast('Automated point-outcome estimates added');return;}if(job.status==='failed'){renderRallyOutcomes([],false);showToast('Point-outcome review could not be completed');return;}renderRallyOutcomes([],true,job);if(job.status==='queued'||job.status==='processing')setTimeout(()=>fetchOutcomeAnalysis(result,attempt+1),5000);}catch(error){console.warn('Outcome analysis sync unavailable',error.message);renderRallyOutcomes([],true,{message:'Reconnecting to the analysis worker',progress:0});setTimeout(()=>fetchOutcomeAnalysis(result,attempt+1),15000);}
}
function renderDiagnosticDownloads(result){const container=$('#diagnosticDownloads');if(!result?.diagnostic_token){container.classList.add('hidden');container.innerHTML='';return;}const base=analysisApi.replace(/\/$/,'');const token=encodeURIComponent(result.diagnostic_token),expires=result.diagnostic_available_until?new Date(result.diagnostic_available_until).toLocaleString():'';container.innerHTML=`<p><strong>24-hour diagnostic copy available</strong>${expires?` · expires ${escapeHtml(expires)}`:''}</p><a class="secondary-button" href="${base}/diagnostics/${token}/overlay" target="_blank" rel="noopener">Download tracking overlay</a><a class="secondary-button" href="${base}/diagnostics/${token}/video" target="_blank" rel="noopener">Download retained source</a>`;container.classList.remove('hidden');}
