const communityTranslations={
  en:{aboutUs:'About us',contactUs:'Contact us',ourStory:'OUR STORY',aboutTitle:'Built from a love of padel—and the questions that follow every match',aboutLead:'Why PadelIQ exists and where we want to take it.',aboutTextOne:'PadelIQ began with a simple frustration: after leaving court, it was hard to understand what had really shaped the match. Memory captures the winners, but not the positioning, recovery and movement patterns behind every point.',aboutTextTwo:'We are building the tool we wanted as players: an accessible coach that turns match footage into clear, useful feedback. The goal is to help every player see their game more objectively, practise with purpose and enjoy the journey of improving.',playerBuilt:'PLAYER-BUILT',aboutQuote:'Make every match part of your improvement journey.',getInTouch:'GET IN TOUCH',contactTitle:'Questions, ideas or partnership enquiries?',contactLead:'We would love to hear from players, coaches, clubs and anyone interested in the future of padel analysis.',firstName:'First name',lastName:'Last name',subject:'Subject',question:'Question',sendMessage:'Send message',stayInLoop:'STAY IN THE LOOP',newsletterTitle:'Follow the PadelIQ journey',newsletterLead:'Get product news, padel performance tips and early access updates.',joinEmailList:'Join the email list',session:'SESSION',signOutTitle:'Sign out of PadelIQ',signOutLead:'End your session securely. You will return to the PadelIQ homepage.'},
  es:{aboutUs:'Sobre nosotros',contactUs:'Contacto',ourStory:'NUESTRA HISTORIA',aboutTitle:'Creado por amor al pádel y por las preguntas que surgen tras cada partido',aboutLead:'Por qué existe PadelIQ y hacia dónde queremos llevarlo.',aboutTextOne:'PadelIQ nació de una frustración sencilla: al salir de la pista era difícil entender qué había definido realmente el partido. La memoria guarda los ganadores, pero no los patrones de posición, recuperación y movimiento.',aboutTextTwo:'Estamos creando la herramienta que queríamos como jugadores: un entrenador accesible que convierte el vídeo en consejos claros y útiles. Queremos que cada jugador vea su juego con objetividad, entrene con intención y disfrute mejorando.',playerBuilt:'CREADO POR JUGADORES',aboutQuote:'Haz que cada partido forme parte de tu mejora.',getInTouch:'HABLEMOS',contactTitle:'¿Preguntas, ideas o propuestas de colaboración?',contactLead:'Nos encantará escuchar a jugadores, entrenadores, clubes y a cualquiera interesado en el futuro del análisis de pádel.',firstName:'Nombre',lastName:'Apellidos',subject:'Asunto',question:'Pregunta',sendMessage:'Enviar mensaje',stayInLoop:'MANTENTE AL DÍA',newsletterTitle:'Sigue el viaje de PadelIQ',newsletterLead:'Recibe noticias, consejos de rendimiento y acceso anticipado.',joinEmailList:'Unirme a la lista'},
  fr:{aboutUs:'À propos',contactUs:'Contact',ourStory:'NOTRE HISTOIRE',aboutTitle:'Né de l’amour du padel et des questions qui suivent chaque match',aboutLead:'Pourquoi PadelIQ existe et où nous voulons aller.',aboutTextOne:'PadelIQ est né d’une frustration simple : après le match, il était difficile de comprendre ce qui l’avait réellement façonné. La mémoire retient les gagnants, mais pas les schémas de placement, de récupération et de déplacement.',aboutTextTwo:'Nous créons l’outil que nous voulions comme joueurs : un coach accessible qui transforme la vidéo en conseils clairs et utiles. Notre objectif est d’aider chacun à voir son jeu objectivement, à s’entraîner avec intention et à aimer progresser.',playerBuilt:'CRÉÉ PAR DES JOUEURS',aboutQuote:'Faites de chaque match une étape de votre progression.',getInTouch:'CONTACTEZ-NOUS',contactTitle:'Questions, idées ou projets de partenariat ?',contactLead:'Nous serions ravis d’échanger avec les joueurs, coachs, clubs et tous ceux qui s’intéressent à l’avenir de l’analyse du padel.',firstName:'Prénom',lastName:'Nom',subject:'Objet',question:'Question',sendMessage:'Envoyer',stayInLoop:'RESTEZ INFORMÉ',newsletterTitle:'Suivez l’aventure PadelIQ',newsletterLead:'Recevez nos actualités, conseils de performance et accès anticipés.',joinEmailList:'Rejoindre la liste'},
  de:{aboutUs:'Über uns',contactUs:'Kontakt',ourStory:'UNSERE GESCHICHTE',aboutTitle:'Aus Liebe zum Padel und den Fragen nach jedem Match entstanden',aboutLead:'Warum es PadelIQ gibt und wohin wir wollen.',aboutTextOne:'PadelIQ entstand aus einer einfachen Frustration: Nach dem Platz war schwer zu erkennen, was das Match wirklich geprägt hatte. Im Gedächtnis bleiben Winner, aber nicht die Muster bei Positionierung, Erholung und Bewegung.',aboutTextTwo:'Wir entwickeln das Werkzeug, das wir uns als Spieler gewünscht haben: einen zugänglichen Coach, der Videos in klares, nützliches Feedback verwandelt. Jeder Spieler soll sein Spiel objektiver sehen, gezielt trainieren und den Weg der Verbesserung genießen.',playerBuilt:'VON SPIELERN ENTWICKELT',aboutQuote:'Mach jedes Match zu einem Teil deiner Entwicklung.',getInTouch:'KONTAKT',contactTitle:'Fragen, Ideen oder Interesse an einer Partnerschaft?',contactLead:'Wir freuen uns auf Nachrichten von Spielern, Trainern, Clubs und allen, die sich für die Zukunft der Padel-Analyse interessieren.',firstName:'Vorname',lastName:'Nachname',subject:'Betreff',question:'Frage',sendMessage:'Nachricht senden',stayInLoop:'BLEIB INFORMIERT',newsletterTitle:'Begleite die PadelIQ-Reise',newsletterLead:'Erhalte Produktneuigkeiten, Leistungstipps und frühen Zugang.',joinEmailList:'E-Mail-Liste beitreten'},
  it:{aboutUs:'Chi siamo',contactUs:'Contatti',ourStory:'LA NOSTRA STORIA',aboutTitle:'Nato dall’amore per il padel e dalle domande dopo ogni partita',aboutLead:'Perché esiste PadelIQ e dove vogliamo arrivare.',aboutTextOne:'PadelIQ nasce da una semplice frustrazione: fuori dal campo era difficile capire cosa avesse davvero determinato la partita. La memoria conserva i colpi vincenti, non gli schemi di posizione, recupero e movimento.',aboutTextTwo:'Stiamo costruendo lo strumento che desideravamo da giocatori: un coach accessibile che trasforma i video in indicazioni chiare e utili. Vogliamo aiutare ogni giocatore a vedere il proprio gioco con obiettività, allenarsi con uno scopo e godersi il miglioramento.',playerBuilt:'CREATO DAI GIOCATORI',aboutQuote:'Rendi ogni partita parte del tuo percorso di crescita.',getInTouch:'CONTATTACI',contactTitle:'Domande, idee o proposte di collaborazione?',contactLead:'Saremo felici di ascoltare giocatori, coach, club e chiunque sia interessato al futuro dell’analisi del padel.',firstName:'Nome',lastName:'Cognome',subject:'Oggetto',question:'Domanda',sendMessage:'Invia messaggio',stayInLoop:'RESTA AGGIORNATO',newsletterTitle:'Segui il viaggio di PadelIQ',newsletterLead:'Ricevi novità, consigli sulle prestazioni e accessi anticipati.',joinEmailList:'Iscriviti alla lista'},
  nl:{aboutUs:'Over ons',contactUs:'Contact',ourStory:'ONS VERHAAL',aboutTitle:'Gebouwd vanuit liefde voor padel en de vragen na elke wedstrijd',aboutLead:'Waarom PadelIQ bestaat en waar we naartoe willen.',aboutTextOne:'PadelIQ begon met een eenvoudige frustratie: na de baan was het lastig te begrijpen wat de wedstrijd echt had bepaald. Je onthoudt de winners, maar niet de patronen in positie, herstel en beweging.',aboutTextTwo:'We bouwen het hulpmiddel dat we zelf als spelers wilden: een toegankelijke coach die wedstrijdbeelden omzet in duidelijke, bruikbare feedback. Zo kan iedere speler objectiever kijken, doelgericht trainen en genieten van vooruitgang.',playerBuilt:'DOOR SPELERS GEBOUWD',aboutQuote:'Maak elke wedstrijd onderdeel van je ontwikkeling.',getInTouch:'NEEM CONTACT OP',contactTitle:'Vragen, ideeën of interesse in samenwerking?',contactLead:'We horen graag van spelers, coaches, clubs en iedereen die geïnteresseerd is in de toekomst van padelanalyse.',firstName:'Voornaam',lastName:'Achternaam',subject:'Onderwerp',question:'Vraag',sendMessage:'Bericht versturen',stayInLoop:'BLIJF OP DE HOOGTE',newsletterTitle:'Volg de reis van PadelIQ',newsletterLead:'Ontvang productnieuws, prestatietips en vroege toegang.',joinEmailList:'Aanmelden voor e-mails'},
  el:{aboutUs:'Σχετικά με εμάς',contactUs:'Επικοινωνία',ourStory:'Η ΙΣΤΟΡΙΑ ΜΑΣ',aboutTitle:'Γεννήθηκε από την αγάπη για το padel και τις ερωτήσεις μετά από κάθε αγώνα',aboutLead:'Γιατί υπάρχει το PadelIQ και πού θέλουμε να φτάσει.',aboutTextOne:'Το PadelIQ ξεκίνησε από μια απλή απογοήτευση: μετά το γήπεδο ήταν δύσκολο να καταλάβουμε τι πραγματικά καθόρισε τον αγώνα. Η μνήμη κρατά τα winners, όχι τα μοτίβα θέσης, επαναφοράς και κίνησης.',aboutTextTwo:'Δημιουργούμε το εργαλείο που θέλαμε ως παίκτες: έναν προσιτό προπονητή που μετατρέπει το βίντεο σε σαφή, χρήσιμη καθοδήγηση. Στόχος είναι κάθε παίκτης να βλέπει αντικειμενικά το παιχνίδι του, να προπονείται με σκοπό και να χαίρεται τη βελτίωση.',playerBuilt:'ΦΤΙΑΓΜΕΝΟ ΑΠΟ ΠΑΙΚΤΕΣ',aboutQuote:'Κάντε κάθε αγώνα μέρος της βελτίωσής σας.',getInTouch:'ΕΠΙΚΟΙΝΩΝΗΣΤΕ',contactTitle:'Ερωτήσεις, ιδέες ή προτάσεις συνεργασίας;',contactLead:'Θα χαρούμε να ακούσουμε παίκτες, προπονητές, συλλόγους και όσους ενδιαφέρονται για το μέλλον της ανάλυσης padel.',firstName:'Όνομα',lastName:'Επώνυμο',subject:'Θέμα',question:'Ερώτηση',sendMessage:'Αποστολή',stayInLoop:'ΜΕΙΝΕΤΕ ΕΝΗΜΕΡΩΜΕΝΟΙ',newsletterTitle:'Ακολουθήστε την πορεία του PadelIQ',newsletterLead:'Λάβετε νέα, συμβουλές απόδοσης και πρώιμη πρόσβαση.',joinEmailList:'Εγγραφή στη λίστα'}
};
