function updateReturnTrainer(scenario){const court=$('#returnCourt');if(!court)return;court.dataset.scenario=scenario;$$('[data-return-scenario]').forEach(button=>button.classList.toggle('active',button.dataset.returnScenario===scenario));const language=localStorage.getItem('padeliqLanguage')||'en',copy=returnScenarioAdvice[language]?.[scenario]||returnScenarioAdvice.en[scenario];$('#returnAdviceTitle').textContent=copy[0];$('#returnAdviceText').textContent=copy[1];}
$$('[data-return-scenario]').forEach(button=>button.addEventListener('click',()=>updateReturnTrainer(button.dataset.returnScenario)));
$$('[data-animation-control]').forEach(button=>button.addEventListener('click',()=>{const card=button.closest('.tactic-video'),paused=card.classList.toggle('paused'),language=localStorage.getItem('padeliqLanguage')||'en';button.textContent=translations[language]?.[paused?'playAnimation':'pauseAnimation']||translations.en[paused?'playAnimation':'pauseAnimation'];}));
function showImprovementSection(section){const selected=['foundations','beginner','pro','returns','drills'].includes(section)?section:'foundations';$$('[data-improve-panel]').forEach(panel=>panel.classList.toggle('hidden',panel.dataset.improvePanel!==selected));$('#improvementSectionSelect').value=selected;localStorage.setItem('padeliqImproveSection',selected);}
$('#improvementSectionSelect').addEventListener('change',event=>showImprovementSection(event.target.value));
function renderTimeGreeting(timeZone){const element=$('#timeGreeting');if(!element)return;let hour=new Date().getHours();try{hour=Number(new Intl.DateTimeFormat('en-GB',{timeZone,hour:'2-digit',hourCycle:'h23'}).format(new Date()));}catch{}const period=hour<12?'morning':hour<18?'afternoon':'evening',language=localStorage.getItem('padeliqLanguage')||'en';element.textContent=translations[language]?.[period]||translations.en[period];}
async function updateTimeGreeting(){const deviceZone=Intl.DateTimeFormat().resolvedOptions().timeZone,cachedZone=sessionStorage.getItem('padeliqTimeZone');renderTimeGreeting(cachedZone||deviceZone);if(cachedZone)return;const controller=new AbortController(),timeout=setTimeout(()=>controller.abort(),2500);try{const response=await fetch('https://ipwho.is/',{signal:controller.signal,cache:'no-store'});const data=await response.json(),ipZone=data?.success!==false?data?.timezone?.id:null;if(ipZone){new Intl.DateTimeFormat('en-GB',{timeZone:ipZone}).format();sessionStorage.setItem('padeliqTimeZone',ipZone);renderTimeGreeting(ipZone);}}catch{}finally{clearTimeout(timeout);}}

const supabaseClient=window.supabase.createClient('https://lsotekuhbrdtfmlyindd.supabase.co','sb_publishable_p7OOWIbybkMLLfRB1w8t6A_UxIXyarb');
function clubText(key){const lang=localStorage.getItem('padeliqLanguage')||'en';return translations[lang]?.[key]||translations.en[key]||key;}
function safeExternalUrl(value){try{const url=new URL(value);return ['http:','https:'].includes(url.protocol)?url.href:'';}catch{return '';}}
function renderClubs(){
  const body=$('#clubTableBody');if(!body)return;
  const query=($('#clubSearch')?.value||'').trim().toLowerCase(),region=$('#clubRegionFilter')?.value||'all';
  const rows=clubDirectoryRows.filter(club=>(region==='all'||club.region===region)&&(!query||[club.name,club.region,club.area].some(value=>value.toLowerCase().includes(query))));
  $('#clubCount').textContent=`${rows.length} ${rows.length===1?'club':'clubs'}`;
  if(!rows.length){body.innerHTML=`<tr><td colspan="6" class="empty-clubs">${escapeHtml(clubText('noClubs'))}</td></tr>`;return;}
  body.innerHTML=rows.map(club=>{const url=safeExternalUrl(club.website);return `<tr><td><span class="club-name">${escapeHtml(club.name)}</span><span class="club-subtext verified-source">✓ ${escapeHtml(clubText('publicSource'))}</span></td><td><span class="region-pill">${escapeHtml(club.region)}</span></td><td>${escapeHtml(club.area)}</td><td><strong>${escapeHtml(club.courts)}</strong></td><td><span class="setting-pill">${escapeHtml(club.setting)}</span></td><td><a class="venue-link" href="${escapeHtml(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(clubText('viewVenue'))} ↗</a></td></tr>`;}).join('');
}
function loadClubs(){renderClubs();}
$('#clubSearch').addEventListener('input',renderClubs);
$('#clubRegionFilter').addEventListener('change',renderClubs);
async function submitContactForm(event){
  event.preventDefault();const form=event.currentTarget,button=$('button[type="submit"]',form),status=$('.form-status',form),data=new FormData(form);button.disabled=true;status.classList.remove('error');status.textContent='Sending…';
  const payload={first_name:String(data.get('firstName')||'').trim(),last_name:String(data.get('lastName')||'').trim(),email:String(data.get('email')||'').trim().toLowerCase(),subject:String(data.get('subject')||'').trim(),question:String(data.get('question')||'').trim(),user_id:currentUser?.id||null,source:form.id==='appContactForm'?'signed_in_app':'homepage',preferred_language:localStorage.getItem('padeliqLanguage')||'en'};
  const {error}=await supabaseClient.from('contact_messages').insert(payload);button.disabled=false;
  if(error){console.warn('Contact submission failed',error.message);status.classList.add('error');status.textContent='We could not send that yet. Please try again.';return;}
  form.reset();if(form.id==='appContactForm'&&currentUser)prefillContactForm();status.textContent='Thank you—your message has been received.';
}
function prefillContactForm(){const form=$('#appContactForm');if(!form||!currentUser)return;const parts=(currentUser.user_metadata?.full_name||'').trim().split(/\s+/);form.elements.firstName.value=parts.shift()||'';form.elements.lastName.value=parts.join(' ');form.elements.email.value=currentUser.email||'';}
$$('#publicContactForm,#appContactForm').forEach(form=>form.addEventListener('submit',submitContactForm));
$('#newsletterForm').addEventListener('submit',async event=>{event.preventDefault();const form=event.currentTarget,button=$('button',form),status=$('.form-status',form),email=form.elements.email.value.trim().toLowerCase();button.disabled=true;status.classList.remove('error');status.textContent='Joining…';const {error}=await supabaseClient.from('newsletter_subscribers').insert({email,preferred_language:localStorage.getItem('padeliqLanguage')||'en',source:'homepage'});button.disabled=false;if(error&&error.code!=='23505'){console.warn('Newsletter signup failed',error.message);status.classList.add('error');status.textContent='We could not add you yet. Please try again.';return;}form.reset();status.textContent='You’re on the list—welcome to PadelIQ!';});
function profileToRow(profile){return {user_id:currentUser.id,full_name:profile.name||'',playing_side:profile.side||null,player_level:profile.level||null,age:profile.age?Number(profile.age):null,gender:profile.gender||null,area:profile.area||null,home_club:profile.homeClub||null,benchmark_consent:Boolean(profile.benchmarkConsent),preferred_language:localStorage.getItem('padeliqLanguage')||'en'};}
function matchToRow(match){return {user_id:currentUser.id,match_name:match.title,played_at:match.isoDate||null,place:match.place||null,court_number:match.court||null,racket:match.racket||null,match_score:match.matchScore||null,position_score:match.score!=null&&Number.isFinite(Number(match.score))?Number(match.score):null,duration_seconds:match.result?.summary?.duration_seconds||null,video_filename:match.videoFilename||null,video_mime_type:match.videoMimeType||null,video_size_bytes:match.videoSizeBytes||null,analysis_status:match.result?'complete':'metadata_only',analysis_result:match.result||null};}
function rowToMatch(row){const played=row.played_at?new Date(`${row.played_at}T12:00:00`):new Date(row.created_at),months=['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];return {id:row.id,remoteId:row.id,date:String(played.getDate()).padStart(2,'0'),month:months[played.getMonth()],isoDate:row.played_at,title:row.match_name,place:row.place||'',court:row.court_number||'',racket:row.racket||'',matchScore:row.match_score||'',score:row.analysis_result&&row.position_score!=null?Number(row.position_score):null,result:row.analysis_result||null,videoFilename:row.video_filename||'',videoMimeType:row.video_mime_type||'',videoSizeBytes:row.video_size_bytes||null,detail:row.analysis_result?'Positioning report':'Match metadata'};}
async function saveProfileToBackend(profile){if(!currentUser)return;const {error}=await supabaseClient.from('profiles').upsert(profileToRow(profile),{onConflict:'user_id'});if(error){backendReady=false;console.warn('Profile database unavailable',error.message);return;}backendReady=true;}
async function saveMatchToBackend(match){if(!currentUser||!backendReady)return false;const row=matchToRow(match);let response;if(match.remoteId)response=await supabaseClient.from('matches').update(row).eq('id',match.remoteId).select().single();else response=await supabaseClient.from('matches').insert(row).select().single();if(response.error){console.warn('Match database save failed',response.error.message);return false;}match.remoteId=response.data.id;const custom=JSON.parse(localStorage.getItem('padeliqMatches')||'[]'),index=custom.findIndex(item=>item.id===match.id);if(index>=0){custom[index].remoteId=response.data.id;localStorage.setItem('padeliqMatches',JSON.stringify(custom));}return true;}
function queueMatchSave(match){const task=saveMatchToBackend(match).finally(()=>{if(pendingMatchSaves.get(match.id)===task)pendingMatchSaves.delete(match.id);});pendingMatchSaves.set(match.id,task);return task;}
async function syncBackendData(user){
  currentUser=user;const [{data:remoteProfile,error:profileError},{data:remoteMatches,error:matchesError}]=await Promise.all([supabaseClient.from('profiles').select('*').eq('user_id',user.id).maybeSingle(),supabaseClient.from('matches').select('*').eq('user_id',user.id).order('played_at',{ascending:false})]);
  if(profileError||matchesError){backendReady=false;console.warn('PadelIQ database schema is not ready');return;}
  backendReady=true;
  if(remoteProfile){const profile={name:remoteProfile.full_name,side:remoteProfile.playing_side||'Left',level:remoteProfile.player_level||'Competitive',age:remoteProfile.age||'',gender:remoteProfile.gender||'',area:remoteProfile.area||'',homeClub:remoteProfile.home_club||'',benchmarkConsent:remoteProfile.benchmark_consent};localStorage.setItem('padeliqProfile',JSON.stringify(profile));loadProfile();}
  const localMatches=JSON.parse(localStorage.getItem('padeliqMatches')||'[]');
  if(remoteMatches?.length){const mapped=remoteMatches.map(rowToMatch),legacy=mapped.filter(isLegacyDemoMatch),userMatches=mapped.filter(match=>!isLegacyDemoMatch(match));if(legacy.length)await supabaseClient.from('matches').delete().eq('user_id',user.id).in('id',legacy.map(match=>match.remoteId));localStorage.setItem('padeliqMatches',JSON.stringify(userMatches));renderMatches();}
  else if(localMatches.length){for(const match of localMatches)await saveMatchToBackend(match);renderMatches();}
  const localProfile=JSON.parse(localStorage.getItem('padeliqProfile')||'null');if(!remoteProfile&&localProfile)await saveProfileToBackend(localProfile);
}
function showLanding(){currentUser=null;backendReady=false;$('#landing').classList.remove('hidden');$('#authView').classList.add('hidden');$('#appShell').classList.add('hidden');if(window.location.hash)history.replaceState(null,'',window.location.pathname+window.location.search);window.scrollTo(0,0);}
function showAuth(mode='signup'){$('#landing').classList.add('hidden');$('#appShell').classList.add('hidden');$('#authView').classList.remove('hidden');switchAuth(mode);window.scrollTo(0,0);}
function switchAuth(mode){['signup','signin','reset','recovery'].forEach(name=>$('#'+name+'Form').classList.toggle('hidden',name!==mode));}
function showApp(user){
  $('#landing').classList.add('hidden');$('#authView').classList.add('hidden');$('#appShell').classList.remove('hidden');
  if(user){currentUser=user;const name=user.user_metadata?.full_name||user.email.split('@')[0];$('#profileEmail').value=user.email;prefillContactForm();const profile=JSON.parse(localStorage.getItem('padeliqProfile')||'null');if(!profile){$('#profileName').value=name;applyProfile(name,user.user_metadata?.level||'Competitive');}syncBackendData(user);}
  updateTimeGreeting();routeTo('dashboard');setTimeout(drawHeatmap,30);
}
$$('[data-auth]').forEach(button=>button.addEventListener('click',()=>showAuth(button.dataset.auth)));
$$('[data-switch-auth]').forEach(button=>button.addEventListener('click',()=>switchAuth(button.dataset.switchAuth)));
$('#backHome').addEventListener('click',showLanding);
async function signOutToHomepage(){const buttons=$$('#logoutButton,#profileLogoutButton');buttons.forEach(button=>button.disabled=true);const {error}=await supabaseClient.auth.signOut();buttons.forEach(button=>button.disabled=false);if(error){showToast('We could not sign you out. Please try again.');return;}showLanding();}
$$('#logoutButton,#profileLogoutButton').forEach(button=>button.addEventListener('click',signOutToHomepage));
$('#deleteAllMatches').addEventListener('click',async()=>{if(!window.confirm('Delete every saved match report, score and analysis result? This removes the records from your account and cannot be undone.'))return;await Promise.allSettled([...pendingMatchSaves.values()]);if(currentUser&&!backendReady){showToast('Cloud deletion is temporarily unavailable. Please try again.');return;}if(currentUser){const {error}=await supabaseClient.from('matches').delete().eq('user_id',currentUser.id);if(error){console.warn('Delete all matches failed',error.message);showToast('Your match data could not be deleted. Please try again.');return;}}localStorage.removeItem('padeliqMatches');localStorage.removeItem('padeliqDeletedDemoMatches');liveAnalysisResult=null;renderMatches();$('#influenceStat').textContent='—';$('#influenceContext').textContent='Useful court area occupied';$('#distanceStat').textContent='—';$('#distanceContext').textContent='Available after real tracking';$('#coverageStat').textContent='—';$('#coverageContext').textContent='Measured frames successfully tracked';drawHeatmap();showToast('All match and video metadata deleted');});

$('#signupForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#signupEmail').value.trim().toLowerCase(),password=$('#signupPassword').value,name=$('#signupName').value.trim();
  const redirectTo=location.origin==='null'?undefined:location.origin;
  const {data,error}=await supabaseClient.auth.signUp({email,password,options:{data:{full_name:name,playing_side:'Left',level:'Competitive'},emailRedirectTo:redirectTo}});
  if(error){$('#signupError').textContent=error.message;return;}
  localStorage.setItem('padeliqProfile',JSON.stringify({name,side:'Left',level:'Competitive'}));loadProfile();
  if(data.session)showApp(data.user);else{$('#signupError').classList.add('auth-success');$('#signupError').textContent='Account created. Check your email to confirm your address, then sign in.';}
});
$('#signinForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#signinEmail').value.trim().toLowerCase(),password=$('#signinPassword').value;
  const {data,error}=await supabaseClient.auth.signInWithPassword({email,password});
  if(error){$('#signinError').textContent=error.message;return;}loadProfile();showApp(data.user);
});
$('#resetForm').addEventListener('submit',async e=>{
  e.preventDefault();const email=$('#resetEmail').value.trim().toLowerCase(),redirectTo=location.origin==='null'?undefined:location.origin;
  const {error}=await supabaseClient.auth.resetPasswordForEmail(email,redirectTo?{redirectTo}:undefined);
  if(error){$('#resetError').textContent=error.message;return;}$('#resetError').classList.add('auth-success');$('#resetError').textContent='Reset link sent. Check your email.';
});
$('#recoveryForm').addEventListener('submit',async e=>{e.preventDefault();const {error}=await supabaseClient.auth.updateUser({password:$('#recoveryPassword').value});if(error){$('#recoveryError').textContent=error.message;return;}$('#recoveryError').classList.add('auth-success');$('#recoveryError').textContent='Password updated successfully.';setTimeout(async()=>{const {data}=await supabaseClient.auth.getUser();showApp(data.user);},900);});

renderMatches();loadProfile();applyLanguage(localStorage.getItem('padeliqLanguage')||'en');showImprovementSection(localStorage.getItem('padeliqImproveSection')||'foundations');
$('#matchDate').valueAsDate=new Date();
supabaseClient.auth.onAuthStateChange((event,session)=>{if(event==='PASSWORD_RECOVERY'){showAuth('recovery');}else if(event==='SIGNED_IN'&&session?.user){showApp(session.user);}else if(event==='SIGNED_OUT'){showLanding();}});
supabaseClient.auth.getSession().then(({data})=>{if(data.session?.user)showApp(data.session.user);else showLanding();});
